ezCollections.Pets =
{
    [4055] = { 2671, 9, 2, "机械松鼠", "机械松鼠的逻辑中心告诉它，为了过冬必须收集并储存坚果和螺栓。", 3, "|cFFFFD200专业：|r工程学" },
    [10673] = { 7385, 7, 2, "灰猫", "冬妮·安萨妮亚计划死后让一只孟买猫给她陪葬。但一位聪明的冒险者能让这只猫的才华得到更好的发挥。", 2, "|cFFFFD200商人：|r冬妮·安萨妮亚|n|cFFFFD200区域：|r艾尔文森林|n|cFFFFD200花费：|r40|TINTERFACE\\MONEYFRAME\\UI-SILVERICON.BLP:0|t" },
    [10674] = { 7384, 7, 2, "黄猫", "冬妮·安萨妮亚会邀请这些猫参加她的茶话会。但她从不提供它们最喜欢的饮料：敌人的眼泪。", 2, "|cFFFFD200商人：|r冬妮·安萨妮亚|n|cFFFFD200区域：|r艾尔文森林|n|cFFFFD200花费：|r40|TINTERFACE\\MONEYFRAME\\UI-SILVERICON.BLP:0|t" },
    [10675] = { 7383, 7, 2, "黑纹灰猫", "奥特兰克古语有云：‘猫有九条命，但只需一条就够了。’", 0, "|cFFFFD200掉落：|r世界掉落|n|cFFFFD200区域：|r奥特兰克山脉" },
    [10676] = { 7382, 7, 2, "虎皮猫", "上一个试图训练这只猫在屋里上厕所的人很快明白了一个道理：弄脏地毯总比把所有东西都撕成碎片要好。", 2, "|cFFFFD200商人：|r冬妮·安萨妮亚|n|cFFFFD200区域：|r艾尔文森林|n|cFFFFD200花费：|r40|TINTERFACE\\MONEYFRAME\\UI-SILVERICON.BLP:0|t" },
    [10677] = { 7380, 7, 2, "黑尾白猫", "以其蓝色的眼睛而闻名。同时也被巨型鱼人视为一种不可多得的美味。", 2, "|cFFFFD200商人：|r商人拉沙德|n|cFFFFD200区域：|r虚空风暴|n|cFFFFD200花费：|r60|TINTERFACE\\MONEYFRAME\\UI-SILVERICON.BLP:0|t" },
    [10678] = { 7381, 7, 2, "黑斑白猫", "睡觉是这只猫第二喜欢的活动。它第一喜欢的是打哈欠。", 2, "|cFFFFD200商人：|r冬妮·安萨妮亚|n|cFFFFD200区域：|r艾尔文森林|n|cFFFFD200花费：|r40|TINTERFACE\\MONEYFRAME\\UI-SILVERICON.BLP:0|t" },
    [10679] = { 7386, 7, 2, "白猫", "‘王后有三只小猫。第一只给了她一只多汁的老鼠。第二只给了她一只美味的野兔。而那只白色的，她最喜欢的那只，献上了她情敌的首级。’", 2, "|cFFFFD200商人：|r小提米|n|cFFFFD200区域：|r暴风城|n|cFFFFD200花费：|r60|TINTERFACE\\MONEYFRAME\\UI-SILVERICON.BLP:0|t" },
    [10680] = { 7390, 2, 2, "红尾鹦鹉", "有人说这只聪明的鸟可以被教会说话——但它足够聪明，知道随时闭紧自己的鸟嘴。", 2, "|cFFFFD200商人：|r纳克|n|cFFFFD200区域：|r荆棘谷|n|cFFFFD200花费：|r40|TINTERFACE\\MONEYFRAME\\UI-SILVERICON.BLP:0|t" },
    [10682] = { 7391, 2, 2, "花羽鹦鹉", "丛林巨魔训练这些鸟模仿求救声，以此引诱毫无防备的旅行者掉入陷阱。", 0, "|cFFFFD200掉落：|r世界掉落|n|cFFFFD200区域：|r荆棘谷" },
    [10683] = { 7387, 2, 2, "绿翼鹦鹉", "作为迪菲亚海盗最宠爱的宠物，这只色彩斑斓的鸟在记住密码、购物清单和饼干食谱方面非常有用。", 0, "|cFFFFD200掉落：|r迪菲亚海盗|n|cFFFFD200区域：|r死亡矿井" },
    [10684] = { 7389, 2, 2, "金翼鹦鹉", "作为藏宝海湾地精最宠爱的宠物，这只色彩斑斓的鸟以其数金币、计算预算以及在合同上撒谎的能力而闻名。", 2, "|cFFFFD200商人：|r纳克|n|cFFFFD200区域：|r荆棘谷|n|cFFFFD200花费：|r40|TINTERFACE\\MONEYFRAME\\UI-SILVERICON.BLP:0|t|n|n|cFFFFD200商人：|r商人拉沙德|n|cFFFFD200区域：|r虚空风暴|n|cFFFFD200花费：|r40|TINTERFACE\\MONEYFRAME\\UI-SILVERICON.BLP:0|t" },
    [10685] = { 7394, 2, 2, "灰色小鸡", "它觉得你尝起来也像鸡肉。", 2, "|cFFFFD200商人：|r玛格斯·特尔萨|n|cFFFFD200区域：|r千针石林|n|cFFFFD200花费：|r1|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [10688] = { 7395, 4, 2, "幽暗城蟑螂", "买蟑螂通常是一时冲动。但它的主人们即使在多次尝试之后，也很难与它分开。", 2, "|cFFFFD200商人：|r商人拉沙德|n|cFFFFD200区域：|r虚空风暴|n|cFFFFD200花费：|r50|TINTERFACE\\MONEYFRAME\\UI-SILVERICON.BLP:0|t|n|n|cFFFFD200商人：|r杰雷米亚·派森|n|cFFFFD200区域：|r幽暗城|n|cFFFFD200花费：|r50|TINTERFACE\\MONEYFRAME\\UI-SILVERICON.BLP:0|t" },
    [10695] = { 7543, 1, 2, "黑龙宝宝", "希望有一天能长得足够大去摧毁村庄，就像妈妈一样。", 0, "|cFFFFD200掉落：|r龙兽幼崽|n|cFFFFD200区域：|r尘泥沼泽，荒芜之地" },
    [10696] = { 7547, 1, 2, "蓝龙宝宝", "像蓝龙军团的其他成员一样，这些古灵精怪的小生物表现出了对奥术魔法的亲和力。", 0, "|cFFFFD200掉落：|r世界掉落|n|cFFFFD200区域：|r艾萨拉" },
    [10697] = { 7544, 1, 2, "红龙宝宝", "这只来自湿地的年轻幼龙正在学习如何狩猎、喷火，以及进行可爱的破坏性狂暴。", 0, "|cFFFFD200掉落：|r世界掉落|n|cFFFFD200区域：|r湿地" },
    [10698] = { 7545, 1, 2, "绿龙宝宝", "这只独特的幼龙曾由绿龙伊萨里奥斯繁育和饲养，如今已在菲拉斯的丛林中安家。", 0, "|cFFFFD200掉落：|r发育中的雏龙，睡梦中的雏龙|n|cFFFFD200区域：|r悲伤沼泽" },
    [10703] = { 7550, 8, 2, "林蛙", "暗月马戏团的商人出售各种稀奇古怪的异域奇珍。他们也卖林蛙。", 2, "|cFFFFD200商人：|r弗里克|n|cFFFFD200世界事件：|r暗月马戏团|n|cFFFFD200花费：|r1|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [10704] = { 7549, 8, 2, "树蛙", "以其强壮的后腿和敏锐的视力而闻名。", 2, "|cFFFFD200商人：|r弗里克|n|cFFFFD200世界事件：|r暗月马戏团|n|cFFFFD200花费：|r1|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [10706] = { 7555, 2, 2, "黑色猫头鹰", "这只深色羽毛的猛禽在泰达希尔的德鲁伊中常被视为厄运的预兆。", 2, "|cFFFFD200商人：|r希尔奈|n|cFFFFD200区域：|r达纳苏斯|n|cFFFFD200花费：|r50|TINTERFACE\\MONEYFRAME\\UI-SILVERICON.BLP:0|t" },
    [10707] = { 7553, 2, 2, "棕色猫头鹰", "暗夜精灵的孩子在他们一岁生日时会收到一根猫头鹰的羽毛作为好运的象征。", 2, "|cFFFFD200商人：|r希尔奈|n|cFFFFD200区域：|r达纳苏斯|n|cFFFFD200花费：|r50|TINTERFACE\\MONEYFRAME\\UI-SILVERICON.BLP:0|t" },
    [10708] = { 7554, 2, 26, "白色猫头鹰", "冬泉谷的熊怪极其珍视这些雄伟生物纯白的羽毛，并将其用于仪式。", 11, "" },
    [10709] = { 14421, 4, 2, "棕色土拨鼠", "错综复杂的地下洞穴系统保护着土拨鼠免受邻居巨大蹄子的踩踏。", 2, "|cFFFFD200商人：|r哈尔帕|n|cFFFFD200区域：|r雷霆崖|n|cFFFFD200花费：|r50|TINTERFACE\\MONEYFRAME\\UI-SILVERICON.BLP:0|t" },
    [10711] = { 7560, 4, 2, "雪兔", "如果你去追逐雪兔，你要知道你肯定会摔跤的。", 2, "|cFFFFD200商人：|r雅尔林·安伯斯提尔|n|cFFFFD200区域：|r丹莫罗|n|cFFFFD200花费：|r20|TINTERFACE\\MONEYFRAME\\UI-SILVERICON.BLP:0|t" },
    [10713] = { 7561, 7, 2, "白鳞蛇", "作为肯瑞托法师最喜爱的同伴，这种爬行动物让人不禁怀疑它到底是一条真正的蛇，还是某种完全不同的东西。", 2, "|cFFFFD200商人：|r布琳妮|n|cFFFFD200区域：|r达拉然|n|cFFFFD200花费：|r50|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [10714] = { 7565, 7, 2, "黑色王蛇", "克萨迪斯无所畏惧地追踪、捕获并训练这些高贵的蛇，让它们在战斗中协助战友。", 2, "|cFFFFD200商人：|r克萨迪斯|n|cFFFFD200区域：|r奥格瑞玛|n|cFFFFD200花费：|r50|TINTERFACE\\MONEYFRAME\\UI-SILVERICON.BLP:0|t" },
    [10716] = { 7562, 7, 2, "棕色蟒蛇", "棕蛇原产于部落控制的领土。它看起来毫不起眼，直到猎物进入它的攻击范围。", 2, "|cFFFFD200商人：|r克萨迪斯|n|cFFFFD200区域：|r奥格瑞玛|n|cFFFFD200花费：|r50|TINTERFACE\\MONEYFRAME\\UI-SILVERICON.BLP:0|t" },
    [10717] = { 7567, 7, 2, "赤练蛇", "赤练蛇在暗矛巨魔中备受青睐，不仅因为其凶猛的天性，还因为其坚定不移的忠诚。", 2, "|cFFFFD200商人：|r商人拉沙德|n|cFFFFD200区域：|r虚空风暴|n|cFFFFD200花费：|r50|TINTERFACE\\MONEYFRAME\\UI-SILVERICON.BLP:0|t|n|n|cFFFFD200商人：|r克萨迪斯|n|cFFFFD200区域：|r奥格瑞玛|n|cFFFFD200花费：|r50|TINTERFACE\\MONEYFRAME\\UI-SILVERICON.BLP:0|t" },
    [12243] = { 8376, 9, 18, "机械小鸡", "别担心；我觉得这个装置的战斗机制和追踪逻辑都已经被禁用了。——奥格索普·奥布诺提斯", 1, "|cFFFFD200任务：|r寻找自己的OOX|n|cFFFFD200区域：|r藏宝海湾|n" },
    [13548] = { 30379, 2, 18, "西部荒野小鸡", "别叫这只鸟“小鸡”，除非你想被弄得一脸蛋清。", 1, "|cFFFFD200任务：|r咕咕咯！|n|cFFFFD200区域：|r西部荒野" },
    [15048] = { 9656, 9, 2, "步行炸弹", "可能具有爆炸性，但绝对很可爱。请远离明火。", 3, "|cFFFFD200专业：|r工程学" },
    [15049] = { 9657, 9, 2, "发条机器人", "这个小巧的维和安全机器人通常配备了最新的奥术消除器和群体打击器。不适合有环保意识的人。", 3, "|cFFFFD200专业：|r工程学" },
    [15067] = { 9662, 1, 2, "精龙宝宝", "在经历了一整天残酷血腥的战斗后，这些可爱的小家伙最喜欢和他们的主人依偎在一起。", 0, "|cFFFFD200掉落：|r世界掉落|n|cFFFFD200区域：|r菲拉斯" },
    [15999] = { 10259, 7, 2050, "座狼幼崽", "座狼是兽人最喜爱的同伴，在战场上极其忠诚。", 1, "|cFFFFD200任务：|r基布雷尔的特殊宠物|n|cFFFFD200区域：|r黑石塔下层" },
    [16450] = { 10598, 7, 2, "烟网小蜘蛛", "尽管出生在黑石塔温暖的高处，但燃网幼蛛可以在大多数环境中存活下来。", 1, "|cFFFFD200任务：|r育母蜘蛛|n|cFFFFD200区域：|r黑石塔下层" },
    [17707] = { 11325, 7, 82, "熊猫宝宝", "这个只有品脱大小的熊猫幼崽受到艾泽拉斯各地冒险者的热烈追捧——尽管它有嗜睡的本性。", 7, "|cFFFFD200促销活动：|r魔兽世界典藏版" },
    [17708] = { 11326, 5, 82, "迷你破坏神", "天堂亦将颤抖，凡人必将哭泣，末日即将——等等，你怎么这么高？", 7, "|cFFFFD200促销活动：|r魔兽世界典藏版" },
    [17709] = { 11327, 4, 82, "跳虫", "作为异虫虫群中一种小巧而凶猛的成员，跳虫是不容小觑的。数量庞大时极其危险。", 7, "|cFFFFD200促销活动：|r魔兽世界典藏版" },
    [19772] = { 12419, 9, 2, "逼真的蟾蜍", "天才工程师们制作了一只极其逼真的林蛙复制品，其成本仅仅是购买真林蛙的十倍。", 3, "|cFFFFD200专业：|r工程学" },
    [23811] = { 14878, 8, 18, "加布林", "传说中的欢跃蛙曾被认为已经灭绝，直到暗月马戏团那些奇怪的麦酒把它们从藏身之处引了出来。", 6, "|cFFFFD200世界事件：|r暗月马戏团" },
    [24696] = { 15186, 0, 82, "奔波尔霸", "这个备受喜爱且极其隐居的鱼人的出现，必定会引来一群人的围观。", 7, "|cFFFFD200促销活动：|r2005年暴雪嘉年华" },
    [24988] = { 15358, 0, 16466, "乐奇", "奔波尔霸迷人的性格和活泼的滑稽动作，保证能抚平挫折感，甚至能点亮最阴郁的心情。", 7, "|cFFFFD200促销活动：|r燃烧的远征典藏版（仅限欧洲地区）|n" },
    [25162] = { 15429, 5, 2, "恶心的软泥怪", "警告：处理恶心的软泥怪时请佩戴手套和护目镜。请勿清洗。会弄脏大多数护甲。", 0, "|cFFFFD200掉落：|r世界掉落|n|cFFFFD200生物：|r泥浆怪和软泥怪" },
    [26010] = { 15699, 9, 2, "安静的机械雪人", "这个巧妙的玩具配备了一个秘密开关，用来禁用它的“安静”模式。幸运的是，即使是制造它的工程师也不知道如何找到它。", 3, "|cFFFFD200专业：|r工程学" },
    [26045] = { 15710, 6, 2, "雪孩子", "他喜欢和你一起跳舞、挥手、玩耍！他在冬幕节过后就会融化，但别担心；总有一天他会再回来的！", 6, "|cFFFFD200世界事件：|r冬幕节|n" },
    [26529] = { 15706, 4, 2, "冬季驯鹿", "再也不想在包装好的节日礼盒里多待一秒钟了。", 6, "|cFFFFD200世界事件：|r冬幕节" },
    [26533] = { 15698, 0, 2, "冬天爷爷的助手", "这些非当季的盟友不知疲倦地工作，为冬幕节做准备，他们希望在一年中的其他时间里不被打扰。", 6, "|cFFFFD200世界事件：|r冬幕节" },
    [26541] = { 15705, 0, 2, "冬天爷爷的小助手", "在盛大的冬幕节庆典期间，这些忠实的同伴将欢乐传播到这片土地的每个角落。而在一年中的其他时间里，他们都很忙。", 6, "|cFFFFD200世界事件：|r冬幕节" },
    [27241] = { 16069, 0, 16466, "咕唧", "格咕咕天生就是个表演者，尽管她仍然神出鬼没，只有在极其罕见的场合才会公开露面。", 7, "|cFFFFD200促销活动：|r欧洲粉丝站促销活动|n" },
    [27570] = { 16085, 0, 2, "小匹德菲特", "爱的力量可能是件危险的事，尤其是当它掌握在一个飞在天上、脾气暴躁的地精手中时。", 6, "|cFFFFD200世界事件：|r情人节|n|cFFFFD200商人：|r可爱商品商人|n|cFFFFD200花费：|r40|TINTERFACE\\ICONS\\INV_ValentinesCard01:0|t|n" },
    [28505] = { 16456, 7, 16466, "波利", "这只幼崽与它的亲戚有许多共同特征，但它的歌唱能力绝对是独一无二的。", 7, "|cFFFFD200促销活动：|riCoke" },
    [28738] = { 16547, 8, 2, "飞毛腿", "稳扎稳打赢得比赛。", 6, "|cFFFFD200世界事件：|r儿童周" },
    [28739] = { 16548, 4, 2, "扭扭先生", "许多人以为“扭扭”指的是这只小猪臀部扭动的动作。当他们看到自己的内脏时，才发现了这个名字的真正含义。", 6, "|cFFFFD200世界事件：|r儿童周" },
    [28740] = { 16549, 4, 2, "小老鼠吱吱", "作为一名聪明的战术家，胡须会装死来愚弄掠食者和收账人。", 6, "|cFFFFD200世界事件：|r儿童周" },
    [28871] = { 16701, 6, 2, "仲夏之魂", "这一小块夏日散发着温暖的夜晚和雷暴的气息。如果你仔细看，也许能认出一张脸。", 6, "|cFFFFD200世界事件：|r仲夏火焰节|n|cFFFFD200商人：|r仲夏商人|n|cFFFFD200花费：|r350|TINTERFACE\\ICONS\\INV_SummerFest_FireFlower:0|t" },
    [30156] = { 17255, 2, 2, "角鹰兽宝宝", "在菲拉斯遭遇鹰身人入侵后，几个角鹰兽筑巢地遭到袭击。数百只幼崽成为孤儿，它们被托付给萨尔多岛的德鲁伊照料。", 8, "|cFFFFD200集换式卡牌：|r艾泽拉斯英雄传" },
    [32298] = { 18381, 1, 82, "虚空龙宝宝", "作为外域虚空龙的后代，这条幼龙仍在成长，努力适应自己作为猎手、保护者以及天空中可爱的恐怖存在的角色。", 7, "|cFFFFD200促销活动：|r燃烧的远征典藏版" },
    [33050] = { 18839, 8, 2, "魔法龙虾", "只有神奇的愿望才能带来神奇的小龙虾。如果你渴望一条鱼，就去钓个愿望吧。", 3, "|cFFFFD200钓鱼：|r钓鱼（430）|n|cFFFFD200区域：|r泰罗卡森林（高地杂鱼群）" },
    [35156] = { 20408, 5, 2, "法力龙宝宝", "虚灵拉沙德在了解到这些神秘生物能够以奥术能量为食后，开始繁育它们。", 2, "|cFFFFD200商人：|r商人拉沙德|n|cFFFFD200区域：|r虚空风暴|n|cFFFFD200花费：|r40|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [35239] = { 20472, 4, 2, "棕兔", "这只小兔兔是它的对手这辈子见过的最可爱的东西。同时也会是最后看到的。", 2, "|cFFFFD200商人：|r商人拉沙德|n|cFFFFD200区域：|r虚空风暴|n|cFFFFD200花费：|r10|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [35907] = { 21010, 2, 2, "蓝色飞蛾", "作为秘蓝岛娇弱的居民，有传言说这种神奇的昆虫拥有治愈的能力。", 2, "|cFFFFD200商人：|r希克斯|n|cFFFFD200区域：|r埃索达|n|cFFFFD200花费：|r50|TINTERFACE\\MONEYFRAME\\UI-SILVERICON.BLP:0|t" },
    [35909] = { 21009, 2, 2, "红色飞蛾", "作为暴露在狂野魔法能量下的产物，这种昆虫是艾泽拉斯飞蛾物种被释放到虚空风暴生态圆顶中后，意外产生的色彩斑斓的结果。", 2, "|cFFFFD200商人：|r商人拉沙德|n|cFFFFD200区域：|r虚空风暴|n|cFFFFD200花费：|r10|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [35910] = { 21008, 2, 2, "黄色飞蛾", "喜欢在雷暴期间飞行，这在秘蓝岛很常见。", 2, "|cFFFFD200商人：|r希克斯|n|cFFFFD200区域：|r埃索达|n|cFFFFD200花费：|r50|TINTERFACE\\MONEYFRAME\\UI-SILVERICON.BLP:0|t" },
    [35911] = { 21018, 2, 2, "白色飞蛾", "喜欢在多雾的夜晚飞行，这在秘蓝岛很常见。", 2, "|cFFFFD200商人：|r希克斯|n|cFFFFD200区域：|r埃索达|n|cFFFFD200花费：|r50|TINTERFACE\\MONEYFRAME\\UI-SILVERICON.BLP:0|t" },
    [36027] = { 21055, 1, 2, "金色龙鹰幼崽", "曾被银月城的龙鹰饲养员所珍视。在夜间很容易被捕食者发现，因此它从小就必须保持警惕。", 2, "|cFFFFD200商人：|r吉兰妮|n|cFFFFD200区域：|r永歌森林|n|cFFFFD200花费：|r50|TINTERFACE\\MONEYFRAME\\UI-SILVERICON.BLP:0|t" },
    [36028] = { 21064, 1, 2, "红色龙鹰幼崽", "与银色龙鹰是死敌；与金色龙鹰关系相当不错。", 2, "|cFFFFD200商人：|r吉兰妮|n|cFFFFD200区域：|r永歌森林|n|cFFFFD200花费：|r50|TINTERFACE\\MONEYFRAME\\UI-SILVERICON.BLP:0|t" },
    [36029] = { 21063, 1, 2, "银色龙鹰幼崽", "一种凶猛的龙鹰，经常被看到从高空俯冲下来捕捉猎物。", 2, "|cFFFFD200商人：|r吉兰妮|n|cFFFFD200区域：|r永歌森林|n|cFFFFD200花费：|r50|TINTERFACE\\MONEYFRAME\\UI-SILVERICON.BLP:0|t" },
    [36031] = { 21056, 1, 2, "蓝色龙鹰幼崽", "由少数仍愿意在虚空风暴进行交易的商人饲养。", 2, "|cFFFFD200商人：|r商人拉沙德|n|cFFFFD200区域：|r虚空风暴|n|cFFFFD200花费：|r10|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [36034] = { 21076, 2, 2, "萤火虫", "通常被孢子人用作光源，在他们穿越赞加沼泽的水道时，这种发光的昆虫能帮助他们避开危险的闪光钉刺者。", 0, "|cFFFFD200掉落：|r闪光钉刺者|n|cFFFFD200区域：|r赞加沼泽" },
    [39181] = { 22445, 2, 18, "迷你鹦鹉", "天爪在变回其真实鸦人形态时释放出的魔法能量，解救了这个可怜的生物——一只被卢安加囚禁起来作为其禽鸟诅咒能量来源的雏鸟。", 1, "|cFFFFD200任务：|r天爪|n|cFFFFD200区域：|r泰罗卡森林|n|n" },
    [39709] = { 22943, 4, 2, "鹿角小飞兔", "许多喝醉的美酒节狂欢者都讲过关于这种神秘生物的故事，但很少有人在第二天早上还能记得那个故事。", 6, "|cFFFFD200世界事件：|r美酒节" },
    [40405] = { 23198, 4, 16466, "金猪", "当好运生气或进食时，它会发出尖叫声。无论哪种情况，你最好别去惹它。", 7, "|cFFFFD200促销活动：|r2007年暴雪全球邀请赛|n" },
    [40549] = { 23234, 7, 2, "蕉蕉", "虽然很不舍得和巴纳纳斯分开，但兰德鲁意识到，当它的父亲穆克拉国王发现它失踪时，如果这只宠物能远离藏宝海湾会更安全。", 8, "|cFFFFD200集换式卡牌：|r穿越黑暗之门" },
    [40613] = { 23231, 5, 2, "威利", "他有点邪恶，但极度嗜睡。别让他靠近小动物！", 6, "|cFFFFD200世界事件：|r儿童周" },
    [40614] = { 23258, 4, 2, "蛋蛋", "辛多雷使用陆行鸟作为坐骑，但这只小陆行鸟在被诊断出患有多种焦虑症后，被认为不适合骑乘。", 6, "|cFFFFD200世界事件：|r儿童周" },
    [40634] = { 23266, 4, 2, "小新", "驯化的雷象被德莱尼人训练为坐骑。在野外，它们因象牙而遭到猎杀。", 6, "|cFFFFD200世界事件：|r儿童周" },
    [40990] = { 23274, 4, 82, "臭臭", "臭臭利用它的气味来驱赶捕食者并吸引猫咪。它在前者方面取得的成功远大于后者。", 5, "|cFFFFD200成就：|r臭气相投|n|cFFFFD200分类：|r综合" },
    [42609] = { 23909, 6, 2, "邪恶的南瓜娃娃", "这个调皮的葫芦喜欢从地里蹦出来，把你吓得屁滚尿流。向南瓜之歌致敬！", 6, "|cFFFFD200世界事件：|r万圣节" },
    [43697] = { 24388, 8, 2, "牙牙", "鳄鱼的皮和肉备受猎人的青睐，但这头野兽非常凶猛，很少会被偷袭得手。", 3, "|cFFFFD200专业：|r钓鱼|n|cFFFFD200区域：|r沙塔斯" },
    [43698] = { 24389, 8, 2, "毒皮", "泥齿和其他鳄鱼一模一样，除了他有极好的幽默感。", 3, "|cFFFFD200专业：|r钓鱼|n|cFFFFD200区域：|r沙塔斯" },
    [43918] = { 24480, 8, 2, "魔汁", "阿曼尼巫医已经把许多受害者变成了青蛙。有些人永远无法恢复。", 0, "|cFFFFD200掉落：|r森林青蛙|n|cFFFFD200区域：|r祖阿曼" },
    [44369] = { 24753, 4, 2, "小丸子", "作为一种害羞的生物，粉色小雷象只会在那些与它交好的人，或者那些醉得无法伤害它的人面前现身。", 6, "|cFFFFD200世界事件：|r美酒节|n|cFFFFD200商人：|r贝尔比·斯威奇|n|cFFFFD200区域：|r丹莫罗|n|cFFFFD200花费：|r100|TINTERFACE\\ICONS\\INV_Misc_Coin_01:0|t|n|n|cFFFFD200商人：|r布利兹·提克维维|n|cFFFFD200区域：|r杜隆塔尔|n|cFFFFD200花费：|r100|TINTERFACE\\ICONS\\INV_Misc_Coin_01:0|t" },
    [45082] = { 25062, 2, 2, "小孢子蝠", "野生孢子蝠是凶猛的生物，但如果从小驯养，它们可以成为忠诚的伙伴。", 2, "|cFFFFD200商人：|r麦卡|n|cFFFFD200区域：|r赞加沼泽|n|cFFFFD200阵营：|r孢子村 - 崇拜|n|cFFFFD200花费：|r30|TINTERFACE\\ICONS\\INV_Mushroom_02:0|t" },
    [45125] = { 25109, 9, 2, "火箭鸡", "当燃烧军团入侵外域时，兰德鲁·长射将这个设计贡献给了战争前线。联盟和部落都拒绝将其投入生产。", 8, "|cFFFFD200集换式卡牌：|r燃烧军团的远征" },
    [45127] = { 25110, 2, 2050, "风筝龙", "比真正的龙安静多了。", 8, "|cFFFFD200集换式卡牌：|r燃烧军团的远征" },
    [45174] = { 25146, 4, 82, "金猪", "这只金猪通过给盟友带来好运来纪念它的祖先。", 7, "|cFFFFD200促销活动：|r招募战友|n" },
    [45175] = { 25147, 4, 82, "银猪", "德鲁伊认为银猪与金猪有着特殊的羁绊，因为这两个品种是在同一时间出现在艾泽拉斯的。", 7, "|cFFFFD200促销活动：|r招募战友" },
    [45890] = { 25706, 6, 2, "灼烧焰灵", "长者萨满警告说，火拉格纳罗斯的缕缕残炎，这些火焰之王的忠实仆从，已经前往熔火前线。建议保持警惕。", 11, "" },
    [46425] = { 26050, 8, 2, "尼尼", "鳄鱼是生活在沿海水域的六足两栖掠食者。考古学家认为它们可能是安戈洛环形山双帆龙的后代。", 3, "|cFFFFD200专业：|r钓鱼|n|cFFFFD200区域：|r沙塔斯" },
    [46426] = { 26056, 8, 2, "莫莫", "在研究鳄鱼物种几年后，著名的垂钓者纳特·帕格断定，鳄鱼幼崽基本上是无害的。", 3, "|cFFFFD200专业：|r钓鱼|n|cFFFFD200区域：|r沙塔斯" },
    [46599] = { 26119, 6, 2, "凤凰宝宝", "作为凤凰之神奥的子嗣，这只幼鸟在出生后立刻就能飞翔。", 0, "|cFFFFD200掉落：|r凯尔萨斯·逐日者|n|cFFFFD200区域：|r魔导师平台" },
    [48406] = { 27217, 1, 16402, "竞争之魂", "这些令人惊叹的生物被奖励给在战斗中取得胜利的英雄，代表着勇敢和力量。", 7, "|cFFFFD200促销活动：|r战场节日" },
    [48408] = { 27346, 1, 16402, "竞争之精华", "只有那些通过伟大行动证明了自己英勇的英雄，才能获赠这些神秘的蛇形生物之一。", 7, "|cFFFFD200促销活动：|r中国PVP赛事" },
    [49964] = { 27914, 5, 2, "灵魂商人", "虚灵灵魂商人会与那些能够从不守规矩的宿主身上释放他们所需精华的人同行。", 8, "|cFFFFD200集换式卡牌：|r寻找伊利丹" },
    [51716] = { 28470, 2, 2, "小虚空鳐", "虚空鳐原产于泰罗卡森林，在雨季产卵。在一次孵化产生的数百个后代中，只有极少数能存活到成年。", 2, "|cFFFFD200商人：|r格雷拉|n|cFFFFD200区域：|r泰罗卡森林|n|cFFFFD200阵营：|r沙塔尔天空卫队 - 崇拜|n|cFFFFD200花费：|r40|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [51851] = { 28513, 3, 16402, "吸血蝙蝠宝宝", "吸血蝙蝠被幽暗城的被遗忘者和祖阿曼的阿曼尼巨魔训练成侦察兵和坐骑。", 0, "|cFFFFD200掉落：|r特雷斯坦·邪蹄|n|cFFFFD200区域：|r卡拉赞" },
    [52615] = { 28883, 3, 82, "霜霜", "当巫妖王的死亡力量将冰牙从死亡中唤醒时意外创造出来的。", 7, "|cFFFFD200促销活动：|r巫妖王之怒典藏版" },
    [53082] = { 29089, 0, 16466, "迷你泰瑞尔", "‘我即是正义化身！’", 7, "|cFFFFD200促销活动：|r2008年暴雪全球邀请赛" },
    [53316] = { 29147, 3, 2, "魅影精灵", "当它感觉到附近生物即将死亡时，头骨会发出刺耳的咯咯笑声。", 2, "|cFFFFD200商人：|r达拉希尔|n|cFFFFD200区域：|r达拉然|n|cFFFFD200花费：|r40|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [54187] = { 24968, 9, 2, "quest Helper（副本任务）", "这个机械战士是冬幕节期间最受欢迎的礼物。不含电池，但绝对带有火箭！", 6, "|cFFFFD200世界事件：|r冬幕节" },
    [55068] = { 29726, 8, 16466, "小叽", "企鹅先生的外表让人回想起一个更文明的时代，那时的决斗者都穿着燕尾服战斗。", 7, "|cFFFFD200促销活动：|r暴雪账号合并" },
    [59250] = { 31575, 4, 2, "巨型下水道老鼠", "你绝对不想在黑暗的小巷里遇到这只老鼠。就这一点而言，其他任何地方你也不想遇到它。", 3, "|cFFFFD200专业：|r钓鱼|n|cFFFFD200区域：|r达拉然" },
    [61348] = { 32589, 2, 2, "小食虱鸟", "与神谕者吉恩的大多数‘神秘的卵’不同，这颗蛋里面居然真的有一个活物。", 0, "|cFFFFD200掉落：|r神秘的卵" },
    [61349] = { 32590, 2, 2, "白色小食虱鸟", "罕见的白化啄鸟在神谕者中备受尊崇。它被看作是暴雨、丰收和处于冬眠中狼獾人的预兆。", 0, "|cFFFFD200掉落：|r神秘的卵" },
    [61350] = { 32592, 1, 2, "始祖龙宝宝", "这些贪婪的幼龙以惊人的速度生长，每天可以吞噬将近自身体重两倍的生肉。", 0, "|cFFFFD200掉落：|r神秘的卵" },
    [61351] = { 32591, 7, 2, "小眼镜蛇", "艾泽拉斯的眼镜蛇以其发作迅速的毒液和迅捷的攻击而闻名。", 0, "|cFFFFD200掉落：|r神秘的卵" },
    [61357] = { 32595, 8, 2, "小潘", "以其睁得大大的眼睛和傲娇的滑行而闻名。", 2, "|cFFFFD200商人：|r塞伊鲁克|n|cFFFFD200区域：|r龙骨荒野|n|cFFFFD200阵营：|r卡鲁亚克 - 崇拜|n|cFFFFD200花费：|r12|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t|n|n|cFFFFD200商人：|r塔奈卡|n|cFFFFD200区域：|r嚎风峡湾|n|cFFFFD200阵营：|r卡鲁亚克 - 崇拜|n|cFFFFD200花费：|r12|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [61472] = { 32643, 6, 82, "肯瑞托魔仆", "为了防止学徒们偷偷使用魔宠来完成他们的杂务，大法师们将召唤这种生物所需的仪式分散隐藏在达拉然各处的几本法术书中。", 5, "|cFFFFD200成就：|r进修|n|cFFFFD200分类：|r综合" },
    [61725] = { 32791, 4, 2, "春兔", "春兔象征着繁衍，而它们也很乐意向你展示原因。", 6, "|cFFFFD200世界事件：|r复活节|n|cFFFFD200商人：|r复活节商人|n|cFFFFD200花费：|r100|TINTERFACE\\ICONS\\Achievement_Noblegarden_Chocolate_Egg:0|t" },
    [61773] = { 32818, 2, 82, "肥胖的火鸡", "他很谦虚，有预见力，而且配上蔓越莓酱非常美味。", 6, "|cFFFFD200世界事件：|r感恩节" },
    [61855] = { 32841, 7, 16466, "暴雪熊宝宝", "这只罕见的熊是为了它小巧的体型和永远年轻的外貌而繁育的。", 5, "|cFFFFD200成就：|r魔兽世界四周年|n|cFFFFD200分类：|r光辉事迹" },
    [61991] = { 32939, 4, 82, "小鹿", "她喜欢有朋友作伴。准确地说，是七十五个朋友。", 5, "|cFFFFD200成就：|r小型宠物店|n|cFFFFD200分类：|r综合" },
    [62491] = { 33188, 6, 2, "泰达希尔树苗", "它总是跳着舞醒来。多快乐的小树啊！", 2, "|cFFFFD200商人：|r鲁克·鹰拳|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r40|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t" },
    [62508] = { 33194, 7, 2, "丹莫罗熊宝宝", "丹莫罗的熊因其顽强的生命力、忠诚和出色的战斗力而备受推崇。它们与矮人在一起的时间丝毫没有削弱它们的凶猛。", 2, "|cFFFFD200商人：|r德里克·布林德比尔德|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r40|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t " },
    [62510] = { 33197, 2, 2, "提瑞斯法蝙蝠宝宝", "能够通过回声定位感知对手的心跳。", 2, "|cFFFFD200商人：|r伊丽莎·基连|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r40|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t" },
    [62513] = { 33198, 7, 2, "杜隆塔尔蝎子", "暴躁的杜隆塔尔蝎子是凶猛的沙漠捕食者。它以仅仅是“偶尔”蜇伤主人而闻名。", 2, "|cFFFFD200商人：|r弗雷卡·血斧|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r40|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t " },
    [62516] = { 33200, 4, 2, "艾尔文小羊羔", "与被变形术变出来的种类不同，真正的纯种羊可是相当吓人的。", 2, "|cFFFFD200商人：|r亚瑟·弗卢下士|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r40|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t " },
    [62542] = { 33219, 4, 2, "莫高雷小陆行鸟", "陆行鸟在开阔地带的速度是无与伦比的，因此捕食者在捕猎它们时依赖于潜行和群体战术。", 2, "|cFFFFD200商人：|r多鲁·雷角|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r40|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t " },
    [62561] = { 33226, 8, 2, "沙滩蟹", "海滩蟹已经通过在海岛沙滩下冬眠来适应北方的寒冷。", 3, "|cFFFFD200专业：|r钓鱼|n|cFFFFD200区域：|r达拉然" },
    [62562] = { 33205, 6, 2, "埃门谷花苗", "埃索达造成的污染所带来的长期影响仍在观察中。", 2, "|cFFFFD200商人：|r伊蕾丝|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r40|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t |n" },
    [62564] = { 33227, 5, 2, "魔法扫帚", "这把扫帚由一名血精灵学徒制造，如果有人能弄清楚怎么让它停下来，它会非常有用。", 2, "|cFFFFD200商人：|r特雷利斯·晨阳|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r40|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t " },
    [62609] = { 33238, 0, 659, "银色侍从", "许多暴风城的年轻人都作为侍从加入了银色北伐军，希望有朝一日能在战场上侍奉圣光。", 1, "|cFFFFD200任务：|r冠军的崛起|n|cFFFFD200区域：|r冰冠冰川" },
    [62674] = { 33274, 9, 2, "机械鸟", "作为年轻侏儒的训练坐骑，机械鸟虽然没有大个头兄弟们的速度，但却拥有它们全部的魅力。", 2, "|cFFFFD200商人：|r里利·斯宾德纳特|n|cFFFFD200区域：|r冰冠冰川" },
    [62746] = { 33239, 0, 403, "银色小步兵", "这些年轻的兽人努力践行银色北伐军的美德：英勇、力量和正直。", 1, "|cFFFFD200任务：|r冠军的崛起|n|cFFFFD200区域：|r冰冠冰川" },
    [63318] = { 33578, 0, 16466, "角斗士莫叽姆斯", "奔波尔巴是所有鱼人角斗士中最令人恐惧的。曾经有一段时间，也是唯一的一个。", 7, "|cFFFFD200促销活动：|r竞技场锦标赛" },
    [63712] = { 33810, 3, 2050, "森金神像", "这实际上是三只宠物合而为一。在召唤它之前，你永远不知道自己会得到什么！", 2, "|cFFFFD200商人：|r萨曼巴|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200花费：|r40|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t|n" },
    [65358] = { 34364, 7, 2, "玳瑁猫", "许多人在战斗前嘲笑这只猫。他们最后的遗言通常是：‘咪咪，过来。’", 2, "|cFFFFD200商人：|r布琳妮|n|cFFFFD200区域：|r达拉然|n|cFFFFD200花费：|r50|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [65381] = { 33530, 0, 18, "好奇的小神谕者", "这种活蹦乱跳的幼年神谕者是鱼人的远亲。", 6, "|cFFFFD200世界事件：|r儿童周" },
    [65382] = { 33529, 0, 18, "好奇的小狼獾人", "尽管体型较小，但狼獾人是诺森德最具攻击性的生物之一。这往往使它们充满好奇心的天性也显得令人生畏。", 6, "|cFFFFD200世界事件：|r儿童周" },
    [65682] = { 34587, 9, 16466, "战斗机器人", "一个由美味的红色或蓝色电解质驱动的战斗机器人。", 7, "|cFFFFD200促销活动：|r激浪促销活动" },
    [66030] = { 34694, 0, 82, "玛润", "只有最稀有的鱼人才能成功穿越空间屏障。而带着像机枪兵那样的先进盔甲和武器回来的，更是少之又少。", 7, "|cFFFFD200促销活动：|r2009年暴雪嘉年华" },
    [66096] = { 34724, 5, 2, "幽光雏龙", "这种极其罕见的法力浮龙因其独特的色彩和温顺的性情而备受珍视。", 2, "|cFFFFD200商人：|r海伦·兰歌|n|cFFFFD200区域：|r冰冠冰川|n|cFFFFD200阵营：|r银色盟约 - 崇拜|n|cFFFFD200花费：|r40|TINTERFACE\\ICONS\\Ability_Paladin_ArtofWar.blp:0|t|n" },
    [66520] = { 34930, 5, 82, "碧玉虎", "被视为幸运的象征，雕刻的玉老虎备受珍视，但驯服一只真正的玉老虎则是一个更大的奖赏。", 7, "|cFFFFD200促销活动：|r招募战友" },
    [67413] = { 35396, 7, 2, "小达尔特", "很少在成年之前离开巢穴。喜欢在附近的刺喉龙巢穴搞恶作剧。", 0, "|cFFFFD200掉落：|r达尔特的巢|n|cFFFFD200区域：|r尘泥沼泽" },
    [67414] = { 35395, 7, 2, "变异幼龙", "对这种紫皮品种的需求大幅减少了哀嚎洞穴附近的迅猛龙数量。", 0, "|cFFFFD200掉落：|r变异守卫，变异破坏者|n|cFFFFD200区域：|r哀嚎洞穴" },
    [67415] = { 35400, 7, 2, "古达克幼龙", "这只狡猾的迅猛龙出生在诺森德的冰天雪地中。严酷的成长环境赋予了它在许多其他生物都会死去的环境中的生存力量。", 0, "|cFFFFD200掉落：|r古达克迅猛龙|n|cFFFFD200区域：|r祖达克" },
    [67416] = { 35387, 7, 2, "小塔克", "跳跃者塔克的这个后代极其敏捷，可以轻松穿梭于复杂的环境中。", 0, "|cFFFFD200掉落：|r塔克的巢|n|cFFFFD200区域：|r贫瘠之地" },
    [67417] = { 35399, 7, 2, "黑曜石幼龙", "这只幼龙因其独特的毛色而备受觊觎。尽管布琳妮对它关爱有加，但这只迅猛龙的野性依然无法被抑制。", 2, "|cFFFFD200商人：|r布琳妮|n|cFFFFD200区域：|r达拉然|n|cFFFFD200花费：|r50|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [67418] = { 35397, 7, 2, "暴掠幼龙", "这些幼龙比其他种类的迅猛龙幼崽更大，它们会长成能造成巨大破坏的巨型爬行动物。", 0, "|cFFFFD200掉落：|r暴掠龙女王的巢|n|cFFFFD200区域：|r安戈洛环形山" },
    [67419] = { 35398, 7, 2, "刺喉幼龙", "刺喉龙的蛋受到它们母亲的严密保护。它们可爱的外表掩盖了其遗传的凶猛。", 0, "|cFFFFD200掉落：|r刺喉龙女王的巢|n|cFFFFD200区域：|r湿地" },
    [67420] = { 35394, 7, 2, "拉扎什幼龙", "拉扎什迅猛龙是丛林中最聪明的掠食者之一，这使得它们深受古拉巴什巨魔的喜爱。", 0, "|cFFFFD200掉落：|r世界掉落|n|cFFFFD200区域：|r荆棘谷" },
    [67527] = { 35468, 5, 16466, "墨玉猎豹", "黑豹在夜间形同隐形，就像潜行的影子，并在黎明时分消失。", 7, "|cFFFFD200促销活动：|r韩国世界事件" },
    [68767] = { 36482, 2, 2, "海象人风筝", "看到这些风筝在诺森德的海岸上空翱翔，就是海象人在附近的明确标志。", 8, "|cFFFFD200集换式卡牌：|r天灾战争" },
    [68810] = { 36511, 5, 2, "幽灵虎幼崽", "充满深情且好奇，这些小猫似乎总能找到最奇特的藏身之处。", 8, "|cFFFFD200集换式卡牌：|r天灾战争" },
    [69002] = { 36607, 1, 16466, "奥妮克希亚龙宝宝", "作为奥妮克希亚的子嗣，这只幼龙决定不重蹈其祖父带来大灾变的覆辙。", 5, "|cFFFFD200成就：|r魔兽世界五周年|n|cFFFFD200分类：|r光辉事迹" },
    [69452] = { 36871, 6, 82, "熔火恶犬宝宝", "熔岩犬可以在火源之地和熔火之心被发现，它们的血统可以追溯到头狼玛格曼达。", 7, "|cFFFFD200促销活动：|r战网安全令绑定|n" },
    [69535] = { 36908, 2, 82, "狮鹫宝宝", "作为蛮锤矮人赠予联盟英雄的礼物，这些幼崽是弗斯塔德及其随从骑乘进入格瑞姆巴托的狮鹫的后代。", 9, "|cFFFFD200游戏内商城|r" },
    [69536] = { 36909, 7, 82, "驭风者宝宝", "无腿的索尔格从没听过那句古老的兽人谚语：‘别扯双足飞龙的尾巴。’", 9, "|cFFFFD200游戏内商城|r" },
    [69539] = { 36910, 5, 82, "紫袍玉虎", "这是一种极其罕见的老虎家族，许多人相信（也许是错误的）某种残留的魔法或其他事件造成了它独特的颜色。", 7, "|cFFFFD200促销活动：|r招募战友" },
    [69541] = { 36911, 0, 82, "熊猫人僧侣", "熊猫人武僧是一位无畏的旅行伴侣，一直在修炼他的武术……除非你请他喝一杯。他认为拒绝是不礼貌的。", 9, "|cFFFFD200游戏内商城|r" },
    [69677] = { 36979, 3, 82, "小克", "生前，克尔苏加德背叛了肯瑞托并创立了诅咒教派。死后，他作为纳克萨玛斯的大巫妖为天灾军团效力。", 9, "|cFFFFD200游戏内商城|r" },
    [70613] = { 37865, 4, 82, "溜溜", "虽然体型很小，但哈巴狗在被激怒时非常危险。", 5, "|cFFFFD200成就：|r寻找更多的人|n|cFFFFD200分类：|r地下城和团队副本" },
    [71840] = { 38374, 5, 2, "毒毒", "这个，呃，‘可爱’的小家伙喜欢和各种小动物一起玩。只是别让它们靠得太近。", 6, "|cFFFFD200世界事件：|r情人节" },
    [74932] = { 40198, 6, 2, "霜娃娃", "虽然它远没有其原来的主人冰霜之王埃霍恩那样具有破坏性，但众所周知，冰霜结节会向毫无防备的冒险者投掷冰冷的雪球。", 6, "|cFFFFD200世界事件：|r仲夏火焰节" },
    [75134] = { 40295, 9, 2, "蓝色发条战士", "杰佩托这一季最畅销的玩具，这台机器人全新的蓝色底盘让艾泽拉斯各地的孩子们都为了这款好斗的战斗机器人而疯狂。", 2, "|cFFFFD200商人：|r世界各地的玩具商人|n|cFFFFD200花费：|r50|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },
    [75613] = { 40624, 1, 82, "星界灵龙", "达拉然的布琳妮是世界上最杰出的异国宠物收藏家之一，她只会将神秘的星界龙奖励给那些痴迷程度与她不相上下的同道中人。", 5, "|cFFFFD200成就：|r小型宠物店|n|cFFFFD200分类：|r宠物对战" },
    [75906] = { 40703, 9, 82, "小拆", "以奥杜尔那个巨大的泰坦原型机为蓝本，这个脾气暴躁的小构造体对它的玩具下手可是很重的。", 9, "|cFFFFD200游戏内商城|r" },
    [75936] = { 40721, 0, 34, "角斗士莫叽姆斯", "奔波尔巴是所有鱼人角斗士中最令人恐惧的。也是唯一的一个。", 11, "" },
    [78381] = { 42078, 9, 82, "迷你雷神", "人类军队的强大火力。雷神总是第一个冲进战场，最后一个撤退！", 7, "|cFFFFD200促销活动：|r星际争霸II：自由之翼典藏版" },
    [23531] = { 14755, 1, 16466, "绿色小神龙", "传说这些生机勃勃的翠绿生物会给它们的主人带来好运并保佑旅途平安。", 7, "|cFFFFD200促销活动：|riCoke 中国" },
    [23530] = { 14756, 1, 16466, "红色小神龙", "据说在秋天看到它会带来好运。以喜欢躲避陌生的生物而闻名。", 7, "|cFFFFD200促销活动：|riCoke 中国" },
    [28487] = { 16445, 0, 82, "塔吉", "特尔奇非常害羞，也很可爱，她更喜欢和亲密的朋友在一起，而不是结交新朋友。", 0, "|cFFFFD200掉落：|r白色鱼人卵" },
    [25018] = { 15361, 0, 16466, "霸波尔奔", "奔波尔霸是世界上最稀有的鱼人种类之一。", 7, "|cFFFFD200促销活动：|r韩国促销活动" },
    [66175] = { 34770, 3, 2, "死亡木偶", "这些被附身的木偶被逝者异想天开的灵魂赋予了生命的表象。", 6, "|cFFFFD200世界事件：|r亡人节" },
    [10699] = { 7546, 1, 2, "青铜龙宝宝", "这只青铜幼龙迷失在时间的长河中，直到一次不寻常的事件才让她得以逃脱。", 0, "|cFFFFD200掉落：|r钢铁部落|n|cFFFFD200区域：|r诅咒之地" },
    [30152] = { 17254, 7, 66, "白色虎崽", "阿莎曼的一只幼崽，由织梦者托付给你。", 2, "|cFFFFD200商人：|r希尔维娅·鹿角|n|cFFFFD200区域：|r瓦尔莎拉|n|cFFFFD200阵营：|r织梦者 - 崇敬|n|cFFFFD200花费：|r500|TINTERFACE\\MONEYFRAME\\UI-GOLDICON.BLP:0|t" },

